{
    "level": "A1–A2",
    "intro": "W tej sekcji szybko przećwiczysz <strong>am / is / are</strong>, przeczenia, krótkie pytania oraz konstrukcje <strong>there is / there are</strong>.",
    "rules": [
        {
            "label": "Present Forms",
            "color": "emerald",
            "text": "Zacznij od form <strong>am / is / are</strong> w prostych zdaniach.",
            "example": "I am late. / She is ready. / They are here."
        },
        {
            "label": "Questions",
            "color": "blue",
            "text": "Z <strong>to be</strong> nie używamy w pytaniach <strong>do / does</strong>.",
            "example": "Are you ready? / Is he at home?"
        },
        {
            "label": "There Is / Are",
            "color": "amber",
            "text": "Potem przećwiczysz wzory do mówienia, co znajduje się w danym miejscu.",
            "example": "There is a book on the table."
        }
    ]
}

{
    "title": "1. Zestaw startowy",
    "intro": "Ta ścieżka prowadzi od najprostszych form do podstawowych pytań i konstrukcji z there.",
    "items": [
        {
            "label": "A1",
            "title": "Present Forms",
            "subtitle": "am / is / are w krótkich zdaniach twierdzących."
        },
        {
            "label": "A1",
            "title": "Negatives",
            "subtitle": "am not, is not, are not i najczęstsze skróty."
        },
        {
            "label": "A1",
            "title": "Questions and Short Answers",
            "subtitle": "Am I...?, Is he...?, Are they...? i krótkie odpowiedzi."
        },
        {
            "label": "A1–A2",
            "title": "There Is / There Are",
            "subtitle": "Jak mówić, że coś jest albo czegoś nie ma w danym miejscu."
        }
    ]
}

{
    "title": "2. Co przećwiczysz",
    "sections": [
        {
            "label": "am / is / are",
            "color": "emerald",
            "description": "Zobaczysz, która forma łączy się z <strong>I</strong>, <strong>he / she / it</strong> oraz <strong>you / we / they</strong>.",
            "examples": [
                {
                    "en": "I am tired. / She is a student. / They are at work.",
                    "ua": "Podstawowe modele do mówienia o stanie, roli i miejscu."
                }
            ]
        },
        {
            "label": "not i pytania",
            "color": "blue",
            "description": "Nauczysz się wstawiać <strong>not</strong> po to be i przenosić formę <strong>przed podmiot</strong> w pytaniach.",
            "examples": [
                {
                    "en": "He is not busy. / Are they ready?",
                    "ua": "Przeczenia i pytania bez dodatkowego operatora."
                }
            ]
        },
        {
            "label": "There is / There are",
            "color": "amber",
            "description": "Powiesz, co jest albo czego nie ma w pokoju, domu, torbie lub mieście.",
            "examples": [
                {
                    "en": "There are two chairs in the kitchen.",
                    "ua": "Mówienie o tym, co znajduje się w danym miejscu."
                }
            ]
        }
    ]
}

{
    "title": "3. Krótko",
    "items": [
        "<strong>Present Forms</strong> daje bazę do zdań z <strong>am / is / are</strong>.",
        "<strong>Negatives</strong> pokazuje formy z <strong>not</strong> oraz skróty <strong>isn't / aren't</strong>.",
        "<strong>Questions and Short Answers</strong> ćwiczy inwersję z <strong>to be</strong> i krótkie odpowiedzi.",
        "<strong>There Is / There Are</strong> pomaga mówić o tym, co znajduje się w danym miejscu.",
        "Razem te lekcje zamykają pierwszy blok A1 dla <strong>to be</strong>."
    ]
}
